EmitIR::operator()(CompoundStmt* obj)
{
  // TODO: 可以在此添加对符号重名的处理
  for (auto&& stmt : obj->subs) {
    if (auto declStmt = stmt->dcst<DeclStmt>()) {
      for (auto&& decl : declStmt->decls) {
        self(decl);
      }
    } else {
      self(stmt);
    }
  }
}"}
